import { GoogleGenAI } from "@google/genai";

export const askGemini = async (prompt: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "You are a friendly and professional tech support assistant for 'Nexus APK'. You help users understand the benefits of the app, how to install APKs safely, and why they should book/pre-register for early access. Keep responses concise and helpful.",
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm having a bit of trouble connecting to my brain right now. Please try again later!";
  }
};

